import java.nio.file.Paths;
import javax.servlet.ServletException;
import javax.servlet.http.HttpServlet;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;

public class UnsafeFileDownloadServlet extends HttpServlet {

    protected void doGet(HttpServletRequest request, HttpServletResponse response)
            throws ServletException, IOException {

        // vulnerable: Directly using user-supplied input to construct a file path
        // This allows for directory traversal attacks if the 'filename' parameter
        // contains sequences like "../"
        String filename = request.getParameter("filename");
        if (filename == null || filename.isEmpty()) {
            response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Filename parameter is missing.");
            return;
        }

        // Construct the full path to the file. This is where the vulnerability lies.
        // An attacker could request "filename=../../../../etc/passwd" to read sensitive files.
        String basePath = "/var/www/data/"; // Base directory for downloadable files
        java.nio.file.Path filePath = Paths.get(basePath + filename);

        if (!Files.exists(filePath) || !Files.isReadable(filePath)) {
            response.sendError(HttpServletResponse.SC_NOT_FOUND, "File not found or not accessible.");
            return;
        }

        response.setContentType("application/octet-stream");
        response.setHeader("Content-Disposition", "attachment; filename=\"" + filePath.getFileName().toString() + "\"");

        try {
            Files.copy(filePath, response.getOutputStream());
        } catch (IOException e) {
            // Log the exception for debugging, but don't expose internal details to the user
            System.err.println("Error serving file: " + e.getMessage());
            response.sendError(HttpServletResponse.SC_INTERNAL_SERVER_ERROR, "Error downloading file.");
        }
    }
}
