// Good code: Demonstrates proper use of Java API to prevent the vulnerability
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import javax.servlet.ServletException;
import javax.servlet.http.HttpServlet;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;

public class SafeFileDownloadServlet extends HttpServlet {

    private static final String BASE_DOWNLOAD_DIRECTORY = "/var/www/data/"; // Base directory for downloadable files

    protected void doGet(HttpServletRequest request, HttpServletResponse response)
            throws ServletException, IOException {

        String requestedFilename = request.getParameter("filename");
        if (requestedFilename == null || requestedFilename.isEmpty()) {
            response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Filename parameter is missing.");
            return;
        }

        // Fix: Sanitize the input and resolve the path securely.
        // This prevents directory traversal attacks.
        Path baseDirPath = Paths.get(BASE_DOWNLOAD_DIRECTORY).toAbsolutePath().normalize();
        Path requestedFilePath = baseDirPath.resolve(requestedFilename).normalize();

        // Ensure the resolved path is still within the base directory
        // This is crucial to prevent directory traversal.
        if (!requestedFilePath.startsWith(baseDirPath)) {
            // Log suspicious activity
            System.err.println("Attempted directory traversal detected for filename: " + requestedFilename);
            response.sendError(HttpServletResponse.SC_FORBIDDEN, "Access denied.");
            return;
        }

        // Further checks for file existence and readability
        if (!Files.exists(requestedFilePath) || !Files.isReadable(requestedFilePath)) {
            response.sendError(HttpServletResponse.SC_NOT_FOUND, "File not found or not accessible.");
            return;
        }

        response.setContentType("application/octet-stream");
        response.setHeader("Content-Disposition", "attachment; filename=\"" + requestedFilePath.getFileName().toString() + "\"");

        try {
            Files.copy(requestedFilePath, response.getOutputStream());
        } catch (IOException e) {
            // Log the exception for debugging, but don't expose internal details to the user
            System.err.println("Error serving file: " + e.getMessage());
            response.sendError(HttpServletResponse.SC_INTERNAL_SERVER_ERROR, "Error downloading file.");
        }
    }
}
